1	using System.Diagnostics;
2	using System.Diagnostics.CodeAnalysis;
3	using System.Linq.Expressions;
4	using Microsoft.CodeAnalysis;
5	using Riok.Mapperly.Abstractions;
6	using Riok.Mapperly.Configuration;
7	using Riok.Mapperly.Configuration.MethodReferences;
8	using Riok.Mapperly.Descriptors.Mappings;
9	using Riok.Mapperly.Descriptors.Mappings.UserMappings;
10	using Riok.Mapperly.Diagnostics;
11	using Riok.Mapperly.Helpers;
12	using Riok.Mapperly.Symbols;
13	
14	namespace Riok.Mapperly.Descriptors;
15	
16	public static class UserMethodMappingExtractor
17	{
18	    internal static IEnumerable<IUserMapping> ExtractUserMappings(SimpleMappingBuilderContext ctx, ITypeSymbol mapperSymbol)
19	    {
20	        // extract user implemented and user defined mappings from mapper
21	        var methods = mapperSymbol.GetMembers().OfType<IMethodSymbol>().Where(method => IsMappingMethodCandidate(ctx, method));
22	        foreach (var method in methods)
23	        {
24	            var mapping =
25	                BuildUserDefinedMapping(ctx, method)
26	                ?? BuildUserImplementedMapping(
27	                    ctx,
28	                    method,
29	                    receiver: null,
30	                    allowPartial: false,
31	                    isStatic: mapperSymbol.IsStatic,
32	                    isExternal: false
33	                );
34	            if (mapping != null)
35	                yield return mapping;
36	        }
37	
38	        // static mapper cannot have base methods
39	        if (mapperSymbol.IsStatic)
40	            yield break;
41	
42	        // extract user implemented mappings from base methods
43	        var baseAndInterfaceMethods = mapperSymbol.AllInterfaces.SelectMany(ctx.SymbolAccessor.GetAllMethods);
44	        if (mapperSymbol.BaseType is { } mapperBaseSymbol)
45	        {
46	            baseAndInterfaceMethods = baseAndInterfaceMethods.Concat(ctx.SymbolAccessor.GetAllMethods(mapperBaseSymbol));
47	        }
48	
49	        baseAndInterfaceMethods = baseAndInterfaceMethods.Distinct(SymbolTypeEqualityComparer.MethodDefault);
50	
51	        foreach (var mapping in BuildUserImplementedMappings(ctx, baseAndInterfaceMethods, null, isStatic: false, isExternal: true))
52	        {
53	            yield return mapping;
54	        }
55	    }
56	
57	    internal static IEnumerable<INewInstanceUserMapping> ExtractNamedUserImplementedNewInstanceMappings(
58	        SimpleMappingBuilderContext ctx,
59	        ITypeSymbol mapperSymbol,
60	        string name
61	    ) => ExtractNamedUserImplementedMappings<INewInstanceUserMapping>(ctx, mapperSymbol, name);
62	
63	    internal static IEnumerable<IExistingTargetUserMapping> ExtractNamedUserImplementedExistingInstanceMappings(
64	        SimpleMappingBuilderContext ctx,
65	        ITypeSymbol mapperSymbol,
66	        string name
67	    ) => ExtractNamedUserImplementedMappings<IExistingTargetUserMapping>(ctx, mapperSymbol, name);
68	
69	    internal static IEnumerable<IUserMapping> ExtractNamedUserImplementedMappings(
70	        SimpleMappingBuilderContext ctx,
71	        IMethodReferenceConfiguration? target
72	    )
73	    {
74	        if (target is null || !target.IsExternal)
75	        {
76	            return [];
77	        }
78	
79	        var type = target.GetTargetType(ctx);
80	        if (type is null)
81	        {
82	            return [];
83	        }
84	
85	        var methods = ctx.SymbolAccessor.GetAllMethods(type).Where(e => ctx.AttributeAccessor.IsMappingNameEqualTo(e, target.Name));
86	        return BuildUserImplementedMappings(
87	            ctx,
88	            methods,
89	            target.GetTargetName(ctx),
90	            type.IsStatic,
91	            isExternal: true,
92	            isDefault: false,
93	            requireAttribute: false
94	        );
95	    }
96	
97	    internal static IEnumerable<IUserMapping> ExtractUserImplementedMappings(
98	        SimpleMappingBuilderContext ctx,
99	        ITypeSymbol type,
100	        string? receiver,
101	        bool isStatic,
102	        bool isExternal
103	    )
104	    {
105	        // Ignore the mapper type itself.
106	        if (SymbolEqualityComparer.Default.Equals(type, ctx.MapperDeclaration.Symbol))
107	        {
108	            return [];
109	        }
110	
111	        var methods = ctx
112	            .SymbolAccessor.GetAllMethods(type)
113	            .Concat(type.AllInterfaces.SelectMany(ctx.SymbolAccessor.GetAllMethods))
114	            .Distinct(SymbolTypeEqualityComparer.MethodDefault);
115	        return BuildUserImplementedMappings(ctx, methods, receiver, isStatic, isExternal);
116	    }
117	
118	    private static IEnumerable<IUserMapping> BuildUserImplementedMappings(
119	        SimpleMappingBuilderContext ctx,
120	        IEnumerable<IMethodSymbol> methods,
121	        string? receiver,
122	        bool isStatic,
123	        bool isExternal,
124	        bool? isDefault = null,
125	        bool requireAttribute = true
126	    )
127	    {
128	        foreach (var method in methods)
129	        {
130	            if (!IsMappingMethodCandidate(ctx, method, requireAttribute))
131	                continue;
132	
133	            // Partial method declarations are allowed for base classes,
134	            // but still treated as user implemented methods,
135	            // since the user should provide an implementation elsewhere.
136	            // This is the case if a partial mapper class is extended.
137	            var mapping = BuildUserImplementedMapping(ctx, method, receiver, true, isStatic, isExternal, isDefault);
138	            if (mapping != null)
139	                yield return mapping;
140	        }
141	    }
142	
143	    private static bool IsMappingMethodCandidate(SimpleMappingBuilderContext ctx, IMethodSymbol method, bool requireAttribute = true)
144	    {
145	        requireAttribute &= !ctx.Configuration.Mapper.AutoUserMappings;
146	
147	        // ignore all non-ordinary methods (e.g. ctor, operators, etc.) and methods declared on the object type (e.g. ToString)
148	        return method.MethodKind == MethodKind.Ordinary
149	            && ctx.SymbolAccessor.IsDirectlyAccessible(method)
150	            && !SymbolEqualityComparer.Default.Equals(method.ReceiverType, ctx.Compilation.ObjectType)
151	            && !ctx.SymbolAccessor.HasAttribute<ObjectFactoryAttribute>(method)
152	            && (
153	                !requireAttribute
154	                || ctx.SymbolAccessor.HasAttribute<UserMappingAttribute>(method)
155	                || method.IsPartialDefinition && ctx.SymbolAccessor.HasAttribute<MapperAttribute>(method.ContainingType)
156	            );
157	    }
158	
159	    private static IUserMapping? BuildUserImplementedMapping(
160	        SimpleMappingBuilderContext ctx,
161	        IMethodSymbol method,
162	        string? receiver,
163	        bool allowPartial,
164	        bool isStatic,
165	        bool isExternal,
166	        bool? isDefault = null
167	    )
168	    {
169	        var userMappingConfig = GetUserMappingConfig(ctx, method, out var hasAttribute);
170	        var valid = !method.IsGenericMethod && (allowPartial || !method.IsPartialDefinition) && (!isStatic || method.IsStatic);
171	
172	        if (!valid || !UserMappingMethodParameterExtractor.BuildParameters(ctx, method, out var parameters))
173	        {
174	            if (!hasAttribute)
175	                return null;
176	
177	            var name = receiver == null ? method.Name : receiver + method.Name;
178	            ctx.ReportDiagnostic(DiagnosticDescriptors.UnsupportedMappingMethodSignature, method, name);
179	            return null;
180	        }
181	
182	        if (userMappingConfig.Ignore == true)
183	            return null;
184	
185	        if (method.ReturnsVoid)
186	        {
187	            return new UserImplementedExistingTargetMethodMapping(
188	                receiver,
189	                method,
190	                userMappingConfig.Default ?? isDefault,
191	                parameters.Source,
192	                parameters.Target!.Value,
193	                parameters.ReferenceHandler,
194	                isExternal
195	            );
196	        }
197	
198	        var (targetType, targetTypeNullability) = BuildTargetType(ctx, method, parameters.Source.Name);
199	        return new UserImplementedMethodMapping(
200	            receiver,
201	            method,
202	            userMappingConfig.Default ?? isDefault,
203	            parameters.Source,
204	            targetType,
205	            parameters.ReferenceHandler,
206	            isExternal,
207	            targetTypeNullability
208	        );
209	    }
210	
211	    private static (ITypeSymbol, UserImplementedMethodMapping.TargetNullability) BuildTargetType(
212	        SimpleMappingBuilderContext ctx,
213	        IMethodSymbol method,
214	        string sourceParameterName
215	    )
216	    {
217	        var targetType = ctx.SymbolAccessor.UpgradeNullable(method.ReturnType);
218	        if (!targetType.IsNullable() || ctx.SymbolAccessor.TryHasAttribute<NotNullAttribute>(method.GetReturnTypeAttributes()))
219	        {
220	            return (targetType, UserImplementedMethodMapping.TargetNullability.NeverNull);
221	        }
222	
223	        var targetNotNullIfSourceNotNull = ctx
224	            .AttributeAccessor.TryAccess<NotNullIfNotNullAttribute>(method.GetReturnTypeAttributes())
225	            .Any(attr => string.Equals(attr.ParameterName, sourceParameterName, StringComparison.Ordinal));
226	        var nullability = targetNotNullIfSourceNotNull
227	            ? UserImplementedMethodMapping.TargetNullability.NotNullIfSourceNotNull
228	            : UserImplementedMethodMapping.TargetNullability.Nullable;
229	        return (targetType, nullability);
230	    }
231	
232	    private static IUserMapping? BuildUserDefinedMapping(SimpleMappingBuilderContext ctx, IMethodSymbol methodSymbol)
233	    {
234	        if (!methodSymbol.IsPartialDefinition)
235	            return null;
236	
237	        if (methodSymbol.IsAsync)
238	        {
239	            ctx.ReportDiagnostic(DiagnosticDescriptors.UnsupportedMappingMethodSignature, methodSymbol, methodSymbol.Name);
240	            return null;
241	        }
242	
243	        if (TryBuildRuntimeTargetTypeMapping(ctx, methodSymbol) is { } userMapping)
244	            return userMapping;
245	
246	        if (TryBuildExpressionMapping(ctx, methodSymbol) is { } expressionMapping)
247	            return expressionMapping;
248	
249	        if (!UserMappingMethodParameterExtractor.BuildParameters(ctx, methodSymbol, out var parameters))
250	        {
251	            ctx.ReportDiagnostic(DiagnosticDescriptors.UnsupportedMappingMethodSignature, methodSymbol, methodSymbol.Name);
252	            return null;
253	        }
254	
255	        if (methodSymbol.IsGenericMethod)
256	            return BuildGenericTypeMapping(ctx, methodSymbol, parameters);
257	
258	        if (parameters.Target.HasValue)
259	        {
260	            return new UserDefinedExistingTargetMethodMapping(
261	                methodSymbol,
262	                parameters.Source,
263	                parameters.Target.Value,
264	                parameters.ReferenceHandler,
265	                ctx.Configuration.Mapper.UseReferenceHandling
266	            )
267	            {
268	                AdditionalSourceParameters = parameters.AdditionalParameters,
269	            };
270	        }
271	
272	        var userMappingConfig = GetUserMappingConfig(ctx, methodSymbol, out _);
273	        if (userMappingConfig.Default == true && parameters.AdditionalParameters.Count > 0)
274	        {
275	            ctx.ReportDiagnostic(
276	                DiagnosticDescriptors.MappingMethodWithAdditionalParametersCannotBeDefaultMapping,
277	                methodSymbol,
278	                methodSymbol.Name
279	            );
280	        }
281	
282	        var mapping = new UserDefinedNewInstanceMethodMapping(
283	            methodSymbol,
284	            parameters.AdditionalParameters.Count == 0 ? userMappingConfig.Default : false,
285	            parameters.Source,
286	            parameters.ReferenceHandler,
287	            ctx.SymbolAccessor.UpgradeNullable(methodSymbol.ReturnType),
288	            ctx.Configuration.Mapper.UseReferenceHandling
289	        )
290	        {
291	            AdditionalSourceParameters = parameters.AdditionalParameters,
292	        };
293	        return mapping;
294	    }
295	
296	    private static IUserMapping BuildGenericTypeMapping(
297	        SimpleMappingBuilderContext ctx,
298	        IMethodSymbol methodSymbol,
299	        MappingMethodParameters parameters
300	    )
301	    {
302	        if (parameters.Target.HasValue)
303	        {
304	            return new UserDefinedExistingTargetGenericTypeMapping(
305	                methodSymbol,
306	                parameters.Source,
307	                parameters.Target.Value,
308	                parameters.ReferenceHandler,
309	                ctx.Configuration.Mapper.UseReferenceHandling
310	            );
311	        }
312	
313	        return new UserDefinedNewInstanceGenericTypeMapping(
314	            methodSymbol,
315	            parameters,
316	            ctx.SymbolAccessor.UpgradeNullable(methodSymbol.ReturnType),
317	            ctx.Configuration.Mapper.UseReferenceHandling,
318	            GetTypeSwitchNullArm(methodSymbol, parameters),
319	            ctx.Compilation.ObjectType.WithNullableAnnotation(NullableAnnotation.NotAnnotated)
320	        );
321	    }
322	
323	    private static UserDefinedNewInstanceRuntimeTargetTypeParameterMapping? TryBuildRuntimeTargetTypeMapping(
324	        SimpleMappingBuilderContext ctx,
325	        IMethodSymbol methodSymbol
326	    )
327	    {
328	        if (methodSymbol.IsGenericMethod)
329	            return null;
330	
331	        if (
332	            !UserMappingMethodParameterExtractor.BuildRuntimeTargetTypeMappingParameters(ctx, methodSymbol, out var runtimeTargetTypeParams)
333	        )
334	        {
335	            return null;
336	        }
337	
338	        return new UserDefinedNewInstanceRuntimeTargetTypeParameterMapping(
339	            methodSymbol,
340	            runtimeTargetTypeParams,
341	            ctx.Configuration.Mapper.UseReferenceHandling,
342	            ctx.SymbolAccessor.UpgradeNullable(methodSymbol.ReturnType),
343	            GetTypeSwitchNullArm(methodSymbol, runtimeTargetTypeParams),
344	            ctx.Compilation.ObjectType.WithNullableAnnotation(NullableAnnotation.NotAnnotated)
345	        );
346	    }
347	
348	    private static UserDefinedExpressionMethodMapping? TryBuildExpressionMapping(
349	        SimpleMappingBuilderContext ctx,
350	        IMethodSymbol methodSymbol
351	    )
352	    {
353	        if (methodSymbol.IsGenericMethod)
354	            return null;
355	
356	        // Only handle parameterless methods - Expression<Func<TSource, TTarget>> mappings
357	        // are meant to be used like IQueryable projections where the source type comes from
358	        // the Expression's type arguments, not from method parameters
359	        if (methodSymbol.Parameters.Length > 0)
360	            return null;
361	
362	        // Check if return type is Expression<Func<TSource, TTarget>>
363	        var returnType = methodSymbol.ReturnType;
364	        if (!returnType.ExtendsOrImplementsGeneric(ctx.Types.Get(typeof(Expression<>)), out var expressionType))
365	            return null;
366	
367	        // Get the Func<TSource, TTarget> type argument
368	        if (expressionType.TypeArguments[0] is not INamedTypeSymbol funcType)
369	            return null;
370	
371	        if (!funcType.ExtendsOrImplementsGeneric(ctx.Types.Get(typeof(Func<,>)), out var funcTypeArgs))
372	            return null;
373	
374	        // Extract source and target types from the Func<TSource, TTarget> type arguments.
375	        // Unlike method parameters, type arguments do not go through SymbolAccessor.WrapMethodParameter,
376	        // so we need to upgrade nullability explicitly.
377	        var sourceType = ctx.SymbolAccessor.UpgradeNullable(funcTypeArgs.TypeArguments[0]);
378	        var targetType = ctx.SymbolAccessor.UpgradeNullable(funcTypeArgs.TypeArguments[1]);
379	
380	        return new UserDefinedExpressionMethodMapping(methodSymbol, sourceType, targetType, ctx.SymbolAccessor.UpgradeNullable(returnType));
381	    }
382	
383	    private static NullFallbackValue? GetTypeSwitchNullArm(IMethodSymbol method, MappingMethodParameters parameters)
384	    {
385	        // target is always the return type for runtime target mappings
386	        Debug.Assert(parameters.Target == null);
387	        var targetType = method.ReturnType;
388	        var sourceType = parameters.Source.Type;
389	
390	        // no polymorphism for extension methods...
391	        // for type parameters:
392	        // for the target type we assume a non-nullable by default
393	        // for the source type we assume a nullable by default
394	        var targetCanBeNull = targetType is ITypeParameterSymbol tpsTarget ? tpsTarget.IsNullable() ?? false : targetType.IsNullable();
395	        var sourceCanBeNull = sourceType is ITypeParameterSymbol tpsSource ? tpsSource.IsNullable() ?? true : sourceType.IsNullable();
396	        return !sourceCanBeNull ? null
397	            : targetCanBeNull ? NullFallbackValue.Default
398	            : NullFallbackValue.ThrowArgumentNullException;
399	    }
400	
401	    private static UserMappingConfiguration GetUserMappingConfig(
402	        SimpleMappingBuilderContext ctx,
403	        IMethodSymbol method,
404	        out bool hasAttribute
405	    )
406	    {
407	        var userMappingAttr = ctx.AttributeAccessor.AccessFirstOrDefault<UserMappingAttribute, UserMappingConfiguration>(method);
408	        hasAttribute = userMappingAttr != null;
409	        return userMappingAttr ?? new UserMappingConfiguration();
410	    }
411	
412	    private static IEnumerable<T> ExtractNamedUserImplementedMappings<T>(
413	        SimpleMappingBuilderContext ctx,
414	        ITypeSymbol mapperSymbol,
415	        string name
416	    )
417	    {
418	        return ctx
419	            .SymbolAccessor.GetAllDirectlyAccessibleMethods(mapperSymbol)
420	            .Where(m => ctx.AttributeAccessor.IsMappingNameEqualTo(m, name) && IsMappingMethodCandidate(ctx, m, requireAttribute: false))
421	            .Select(m => BuildUserImplementedMapping(ctx, m, null, allowPartial: true, isStatic: mapperSymbol.IsStatic, isExternal: false))
422	            .OfType<T>();
423	    }
424	}
