168	        /// Contains mappings to build and already built mappings.
169	        /// </summary>
170	        private readonly Dictionary<TypeMappingKey, T> _defaultMappings = new();
171	
172	        /// <summary>
173	        /// Registered user mappings by their methods.
174	        /// </summary>
175	        private readonly Dictionary<IMethodSymbol, TUserMapping> _userMappingsByMethod = new(SymbolEqualityComparer.Default);
176	
177	        /// <summary>
178	        /// All user mappings registered in this instance, indexed by source/target type pair.
179	        /// Used as the canonical source for parameterized and diagnostic queries.
180	        /// </summary>
181	        private readonly ListDictionary<TypeMappingKey, TUserMapping> _userMappings = new();
182	
183	        /// <summary>
184	        /// Named mappings by their names.
185	        /// </summary>
186	        private readonly Dictionary<string, TUserMapping> _namedMappings = new();
187	
188	        /// <summary>
189	        /// Duplicated mapping names.
190	        /// </summary>
191	        private readonly HashSet<string> _duplicatedMappingNames = [];
192	
193	        /// <summary>
194	        /// All mapping type keys which for which an explicit default mapping is configured.
195	        /// </summary>
196	        private readonly HashSet<TypeMappingKey> _explicitDefaultMappingKeys = [];
197	
198	        /// <summary>
199	        /// All mapping keys for which <see cref="Find(TypeMappingKey, ParameterScope?)"/> was called and returned a non-null result.
200	        /// </summary>
201	        private readonly HashSet<TypeMappingKey> _usedMappingKeys = [];
202	
203	        /// <summary>
204	        /// All mappings for which <see cref="FindNamed"/> was called and returned a non-null result.
205	        /// </summary>
206	        private readonly HashSet<TUserMapping> _referencedNamedMappings = [];
207	
208	        /// <inheritdoc cref="_defaultMappings"/>
209	        public IReadOnlyDictionary<TypeMappingKey, T> DefaultMappings => _defaultMappings;
210	
211	        /// <summary>
212	        /// All registered user mappings.
213	        /// </summary>
214	        public IEnumerable<TUserMapping> UserMappings => _userMappingsByMethod.Values;
215	
216	        /// <summary>
217	        /// Returns user mappings that are duplicates (same type pair, no explicit default)
218	        /// for type-pairs which are actually in use and not referenced by name.
219	        /// Within each group, the first mapping (which won the _defaultMappings race) is excluded.
220	        /// </summary>
221	        public IEnumerable<TUserMapping> UsedDuplicatedNonDefaultNonReferencedUserMappings =>
222	            _userMappings
223	                .AsDictionary()
224	                .Where(g => _usedMappingKeys.Contains(g.Key) && !_explicitDefaultMappingKeys.Contains(g.Key))
225	                .Select(g => g.Value.Where(m => !m.IsExternal && !m.Default.HasValue))
226	                .Where(g => g.Skip(1).Any())
227	                .SelectMany(g => g.Skip(1))
228	                .Where(m => !_referencedNamedMappings.Contains(m));
229	
230	        public TUserMapping? FindUserMapping(IMethodSymbol method) => _userMappingsByMethod.GetValueOrDefault(method);
231	
232	        public T? Find(TypeMappingKey mappingKey, ParameterScope? scope = null)
233	        {
234	            if (scope is { IsEmpty: false })
235	                return FindByParameters(mappingKey, scope);
236	
237	            if (_defaultMappings.TryGetValue(mappingKey, out var mapping))
238	            {
239	                _usedMappingKeys.Add(mappingKey);
240	            }
241	
242	            return mapping;
243	        }
244	
245	        public T? FindNamed(string name, out bool ambiguousName)
246	        {
247	            ambiguousName = false;
248	            if (_namedMappings.TryGetValue(name, out var mapping))
249	            {
250	                ambiguousName = _duplicatedMappingNames.Contains(name);
251	                _referencedNamedMappings.Add(mapping);
252	            }
253	
254	            return mapping;
255	        }
256	
257	        private TUserMapping? FindByParameters(TypeMappingKey key, ParameterScope scope)
258	        {
259	            var candidates = _userMappings.GetOrEmpty(key).Where(m => m is IParameterizedMapping { AdditionalSourceParameters.Count: > 0 });
260	
261	            foreach (var mapping in candidates)
262	            {
263	                if (scope.TryUseParameters(mapping))
264	                    return mapping;
265	            }
266	
267	            return default;
268	        }
269	
270	        public void AddNamedUserMapping(string? name, TUserMapping mapping)
271	        {
272	            var isNewUserMappingMethod = _userMappingsByMethod.TryAdd(mapping.Method, mapping);
273	
274	            if (name == null)
275	                return;
276	
277	            if (_namedMappings.TryAdd(name, mapping))
278	                return;
279	
280	            // if the name is duplicated
281	            // and there is already another user mapping instance registered for the same method symbol,
282	            // this name is not considered duplicated as the mapping just got re-discovered
283	            if (isNewUserMappingMethod)
284	            {
285	                _duplicatedMappingNames.Add(name);
286	            }
287	        }
288	
289	        public MappingCollectionAddResult TryAddAsDefault(T mapping, TypeMappingConfiguration config)
290	        {
291	            var mappingKey = new TypeMappingKey(mapping, config);
292	            var result = _defaultMappings.TryAdd(mappingKey, mapping)
293	                ? MappingCollectionAddResult.Added
294	                : MappingCollectionAddResult.NotAddedDuplicated;
295	            AddAdditionalMappings(mapping, config);
296	            return result;
297	        }
298	
299	        public MappingCollectionAddResult AddUserMapping(TUserMapping mapping, bool? isDefault, string? name)
300	        {
301	            AddNamedUserMapping(name, mapping);
302	            _userMappings.Add(new TypeMappingKey(mapping), mapping);
303	
304	            return isDefault switch
305	            {
306	                // the mapping is not a default mapping.
307	                false => MappingCollectionAddResult.NotAddedIgnored,
308	
309	                // if a default mapping was already added for this type-pair
310	                // ignore the current one and return duplicated
311	                // otherwise overwrite the existing with the new default one.
312	                true => AddDefaultUserMapping(mapping),
313	
314	                // no default value specified
315	                // add it if none exists yet
316	                null => TryAddAsDefault(mapping, TypeMappingConfiguration.Default),
317	            };
318	        }
319	
320	        private MappingCollectionAddResult AddDefaultUserMapping(T mapping)
321	        {
322	            var mappingKey = new TypeMappingKey(mapping);
323	            if (!_explicitDefaultMappingKeys.Add(mappingKey))
324	                return MappingCollectionAddResult.NotAddedDuplicated;
325	
326	            _defaultMappings[mappingKey] = mapping;
327	            AddAdditionalMappings(mapping, TypeMappingConfiguration.Default);
328	            return MappingCollectionAddResult.Added;
329	        }
330	
331	        private void AddAdditionalMappings(T mapping, TypeMappingConfiguration config)
332	        {
333	            foreach (var additionalKey in mapping.BuildAdditionalMappingKeys(config))
334	            {
335	                _defaultMappings.TryAdd(additionalKey, mapping);
336	            }
337	        }
338	    }
339	}
