1	using Microsoft.CodeAnalysis;
2	using Microsoft.CodeAnalysis.CSharp;
3	using Microsoft.CodeAnalysis.CSharp.Syntax;
4	using Riok.Mapperly.Abstractions.ReferenceHandling;
5	using Riok.Mapperly.Descriptors.Mappings.ExistingTarget;
6	using Riok.Mapperly.Emit;
7	using Riok.Mapperly.Emit.Syntax;
8	using Riok.Mapperly.Helpers;
9	using Riok.Mapperly.Symbols;
10	using static Microsoft.CodeAnalysis.CSharp.SyntaxFactory;
11	using static Riok.Mapperly.Emit.Syntax.SyntaxFactoryHelper;
12	
13	namespace Riok.Mapperly.Descriptors.Mappings.UserMappings;
14	
15	/// <summary>
16	/// A user defined generic existing target mapping method,
17	/// which can have a generic source parameter,
18	/// a generic target parameter or both.
19	/// Maps to an existing target object instance.
20	/// Similar to <see cref="UserDefinedNewInstanceGenericTypeMapping"/> but for existing target mappings.
21	/// </summary>
22	public class UserDefinedExistingTargetGenericTypeMapping(
23	    IMethodSymbol method,
24	    MethodParameter sourceParameter,
25	    MethodParameter targetParameter,
26	    MethodParameter? referenceHandlerParameter,
27	    bool enableReferenceHandling
28	) : MethodMapping(method, sourceParameter, referenceHandlerParameter, targetParameter.Type), IExistingTargetUserMapping
29	{
30	    private const string SourceName = "source";
31	    private const string TargetName = "target";
32	    private const string GetTypeMethodName = nameof(GetType);
33	
34	    private readonly List<IExistingTargetMapping> _mappings = [];
35	
36	    public new IMethodSymbol Method { get; } = method;
37	
38	    /// <summary>
39	    /// Always false, as this cannot be called by other mappings,
40	    /// this can never be the default.
41	    /// </summary>
42	    public bool? Default => false;
43	
44	    public bool IsExternal => false;
45	
46	    private MethodParameter TargetParameter { get; } = targetParameter;
47	
48	    /// <summary>
49	    /// The reference handling is enabled but is only internal to this method.
50	    /// No reference handler parameter is passed.
51	    /// </summary>
52	    private bool InternalReferenceHandlingEnabled => enableReferenceHandling && ReferenceHandlerParameter == null;
53	
54	    public void AddMappings(IEnumerable<IExistingTargetMapping> mappings) => _mappings.AddRange(mappings);
55	
56	    public override ExpressionSyntax Build(TypeMappingBuildContext ctx) =>
57	        throw new InvalidOperationException($"{nameof(UserDefinedExistingTargetGenericTypeMapping)} does not support {nameof(Build)}");
58	
59	    public IEnumerable<StatementSyntax> Build(TypeMappingBuildContext ctx, ExpressionSyntax target)
60	    {
61	        return ctx.SyntaxFactory.SingleStatement(
62	            ctx.SyntaxFactory.Invocation(
63	                MethodName,
64	                SourceParameter.WithArgument(ctx.Source),
65	                TargetParameter.WithArgument(target),
66	                ReferenceHandlerParameter?.WithArgument(ctx.ReferenceHandler)
67	            )
68	        );
69	    }
70	
71	    public override MethodDeclarationSyntax BuildMethod(SourceEmitterContext ctx)
72	    {
73	        var methodSyntax = (MethodDeclarationSyntax)Method.DeclaringSyntaxReferences.First().GetSyntax();
74	        return base.BuildMethod(ctx)
75	            .WithTypeParameterList(methodSyntax.TypeParameterList)
76	            .WithConstraintClauses(List(GetTypeParameterConstraintClauses()));
77	    }
78	
79	    public override IEnumerable<StatementSyntax> BuildBody(TypeMappingBuildContext ctx)
80	    {
81	        // if the source or target type is nullable or is an unconstrained generic type parameter
82	        // (which could be null at runtime), add a null guard.
83	        // if (source == null || target == null)
84	        //    return;
85	        if (SourceType.IsNullable() || TargetType.IsNullable() || CanBeNull(SourceType) || CanBeNull(TargetType))
86	        {
87	            yield return BuildNullGuard(ctx);
88	        }
89	
90	        // if reference handling is enabled and no reference handler parameter is declared
91	        // a new reference handler is instantiated and used.
92	        if (InternalReferenceHandlingEnabled)
93	        {
94	            // var refHandler = new RefHandler();
95	            var referenceHandlerName = ctx.NameBuilder.New(DefaultReferenceHandlerParameterName);
96	            var createRefHandler = ctx.SyntaxFactory.CreateInstance<PreserveReferenceHandler>();
