9	public static class InlineExpressionMappingBuilder
10	{
11	    /// <summary>
12	    /// Builds an inline expression delegate mapping for the given source and target types.
13	    /// This is used by both queryable projection mappings and expression mappings.
14	    /// </summary>
15	    /// <param name="ctx">The mapping builder context.</param>
16	    /// <param name="sourceType">The source type to map from.</param>
17	    /// <param name="targetType">The target type to map to.</param>
18	    /// <returns>The built mapping, or <see langword="null"/> if no mapping could be created.</returns>
19	    public static INewInstanceMapping? TryBuildInlineMappingForExpression(
20	        MappingBuilderContext ctx,
21	        ITypeSymbol sourceType,
22	        ITypeSymbol targetType
23	    )
24	    {
25	        var userMapping = ctx.FindMapping(new TypeMappingKey(sourceType, targetType), ctx.ParameterScope) as IUserMapping;
26	        var mappingKey = BuildMappingKey(ctx, sourceType, targetType);
27	        var inlineCtx = new InlineExpressionMappingBuilderContext(ctx, userMapping, mappingKey);
28	
29	        if (userMapping is UserImplementedMethodMapping && inlineCtx.FindMapping(sourceType, targetType) is { } inlinedUserMapping)
30	        {
31	            return inlinedUserMapping;
32	        }
33	
34	        var mapping = inlineCtx.BuildMapping(mappingKey, MappingBuildingOptions.KeepUserSymbol);
35	        if (mapping == null)
36	            return null;
37	
38	        if (ctx.Configuration.Mapper.UseReferenceHandling)
39	        {
40	            ctx.ReportDiagnostic(DiagnosticDescriptors.QueryableProjectionMappingsDoNotSupportReferenceHandling);
41	        }
42	
43	        return mapping;
44	    }
45	
46	    /// <summary>
47	    /// Tries to inline a given mapping.
48	    /// This works as long as the user implemented methods
49	    /// follow the expression tree limitations:
50	    /// https://learn.microsoft.com/en-us/dotnet/csharp/advanced-topics/expression-trees/#limitations
51	    /// </summary>
52	    /// <param name="ctx">The context.</param>
53	    /// <param name="mapping">The mapping.</param>
54	    /// <returns>The inlined mapping or <c>null</c> if it could not be inlined.</returns>
55	    public static INewInstanceMapping? TryBuildMapping(InlineExpressionMappingBuilderContext ctx, UserImplementedMethodMapping mapping)
56	    {
57	        if (mapping.Method.DeclaringSyntaxReferences is not [var methodSyntaxRef])
58	        {
59	            return null;
60	        }
61	
62	        var methodSyntax = methodSyntaxRef.GetSyntax();
63	
64	        if (methodSyntax is not MethodDeclarationSyntax { ParameterList.Parameters: [var sourceParameter, ..] } methodDeclaration)
65	        {
66	            return null;
67	        }
68	
69	        var bodyExpression = TryGetBodyExpression(methodDeclaration);
70	        if (bodyExpression == null)
71	        {
72	            return null;
73	        }
74	
75	        var semanticModel = ctx.GetSemanticModel(methodSyntax.SyntaxTree);
76	        if (semanticModel is null)
77	        {
78	            return null;
79	        }
80	
81	        var inlineRewriter = new InlineExpressionRewriter(semanticModel, ctx.FindNewInstanceMapping);
82	        bodyExpression = (ExpressionSyntax?)bodyExpression.Accept(inlineRewriter);
83	        if (bodyExpression == null || !inlineRewriter.CanBeInlined)
84	        {
85	            return null;
86	        }
87	
88	        return new UserImplementedInlinedExpressionMapping(mapping, sourceParameter, inlineRewriter.MappingInvocations, bodyExpression);
89	    }
90	
91	    private static ExpressionSyntax? TryGetBodyExpression(MethodDeclarationSyntax methodDeclaration)
92	    {
93	        return methodDeclaration switch
94	        {
95	            // => expression
96	            { ExpressionBody: { } body } => body.Expression,
97	
98	            // { return expression; }
99	            { Body.Statements: [ReturnStatementSyntax singleStatement] } => singleStatement.Expression,
100	
101	            // { var dest = expression; return dest; }
102	            {
103	                Body.Statements: [
104	                    LocalDeclarationStatementSyntax
105	                    {
106	                        Declaration.Variables: [{ Initializer: { } variableInitializer } variableDeclarator]
107	                    },
108	                    ReturnStatementSyntax { Expression: IdentifierNameSyntax identifierName },
109	                ]
110	            } when identifierName.Identifier.Value == variableDeclarator.Identifier.Value => variableInitializer.Value,
111	
112	            _ => null,
113	        };
114	    }
115	
116	    private static TypeMappingKey BuildMappingKey(MappingBuilderContext ctx, ITypeSymbol sourceType, ITypeSymbol targetType)
117	    {
118	        // if nullable reference types are disabled
119	        // and there was no explicit nullable annotation,
120	        // the non-nullable variant is used here.
121	        // Otherwise, this would lead to a select like source.Select(x => x == null ? throw ... : new ...)
122	        // which is not expected in this case.
123	        // see also https://github.com/riok/mapperly/issues/1196
124	        sourceType = ctx.SymbolAccessor.NonNullableIfNullableReferenceTypesDisabled(sourceType, ctx.UserMapping?.SourceType);
125	        targetType = ctx.SymbolAccessor.NonNullableIfNullableReferenceTypesDisabled(targetType, ctx.UserMapping?.TargetType);
126	
127	        return new TypeMappingKey(sourceType, targetType);
