1	using Microsoft.CodeAnalysis;
2	using Microsoft.CodeAnalysis.CSharp;
3	using Microsoft.CodeAnalysis.CSharp.Syntax;
4	using Riok.Mapperly.Helpers;
5	using static Microsoft.CodeAnalysis.CSharp.SyntaxFactory;
6	
7	namespace Riok.Mapperly.Descriptors.Mappings.UserMappings;
8	
9	/// <summary>
10	/// An inlined version of a <see cref="UserImplementedMethodMapping"/>.
11	/// Does not support reference handling and has several other limitations,
12	/// <see cref="InlineExpressionRewriter"/>.
13	/// </summary>
14	/// <param name="userMapping">The original user mapping.</param>
15	/// <param name="sourceParameter">The source parameter of the user mapping. This will probably be rewritten when inlining.</param>
16	/// <param name="mappingInvocations">Mapping invocations to be inlined.</param>
17	/// <param name="mappingBody">The prepared user written mapping body code (rewritten by <see cref="InlineExpressionRewriter"/>.</param>
18	public class UserImplementedInlinedExpressionMapping(
19	    UserImplementedMethodMapping userMapping,
20	    ParameterSyntax sourceParameter,
21	    IReadOnlyDictionary<SyntaxAnnotation, INewInstanceMapping> mappingInvocations,
22	    ExpressionSyntax mappingBody
23	) : NewInstanceMapping(userMapping.SourceType, userMapping.TargetType), INewInstanceUserMapping
24	{
25	    public IMethodSymbol Method => userMapping.Method;
26	    public bool? Default => userMapping.Default;
27	    public bool IsExternal => userMapping.IsExternal;
28	
29	    public override ExpressionSyntax Build(TypeMappingBuildContext ctx)
30	    {
31	        var rewriter = new InliningRewriter(ctx, sourceParameter, mappingInvocations, ctx.NameBuilder);
32	        return (ExpressionSyntax)rewriter.Visit(mappingBody);
33	    }
34	
35	    private class InliningRewriter(
36	        TypeMappingBuildContext ctx,
37	        ParameterSyntax sourceParameter,
38	        IReadOnlyDictionary<SyntaxAnnotation, INewInstanceMapping> mappingInvocations,
39	        UniqueNameBuilder nameBuilder,
40	        Dictionary<string, string>? replacements = null
41	    ) : CSharpSyntaxRewriter
42	    {
43	        private readonly Dictionary<string, string> _replacements =
44	            replacements != null ? new Dictionary<string, string>(replacements) : new();
45	
46	        public override SyntaxNode VisitSimpleLambdaExpression(SimpleLambdaExpressionSyntax node)
47	        {
48	            var scopedNameBuilder = nameBuilder.NewScope();
49	            var rewriter = new InliningRewriter(ctx, sourceParameter, mappingInvocations, scopedNameBuilder, _replacements);
50	
51	            var oldName = node.Parameter.Identifier.Text;
52	            var isRenamed = scopedNameBuilder.NewIfNeeded(oldName, out var newName);
53	            rewriter._replacements[oldName] = newName;
54	
55	            var newBody = (CSharpSyntaxNode)rewriter.Visit(node.Body);
56	            var newNode = node.WithBody(newBody);
57	            if (isRenamed)
58	            {
59	                newNode = newNode.WithParameter(
60	                    node.Parameter.WithIdentifier(Identifier(newName).WithTriviaFrom(node.Parameter.Identifier))
61	                );
62	            }
63	
64	            return newNode;
65	        }
66	
67	        public override SyntaxNode VisitParenthesizedLambdaExpression(ParenthesizedLambdaExpressionSyntax node)
68	        {
69	            var scopedNameBuilder = nameBuilder.NewScope();
70	            var rewriter = new InliningRewriter(ctx, sourceParameter, mappingInvocations, scopedNameBuilder, _replacements);
71	
72	            var updatedParameters = new List<ParameterSyntax>(node.ParameterList.Parameters.Count);
73	            var anyRenamed = false;
74	
75	            foreach (var parameter in node.ParameterList.Parameters)
76	            {
77	                var oldName = parameter.Identifier.Text;
78	                var isRenamed = scopedNameBuilder.NewIfNeeded(oldName, out var newName);
79	                rewriter._replacements[oldName] = newName;
80	
81	                if (isRenamed)
82	                {
83	                    updatedParameters.Add(parameter.WithIdentifier(Identifier(newName).WithTriviaFrom(parameter.Identifier)));
84	                    anyRenamed = true;
85	                }
86	                else
87	                {
88	                    updatedParameters.Add(parameter);
89	                }
90	            }
91	
92	            var newBody = (CSharpSyntaxNode)rewriter.Visit(node.Body);
93	
94	            var newNode = node.WithBody(newBody);
95	            if (anyRenamed)
96	            {
97	                newNode = newNode.WithParameterList(
98	                    node.ParameterList.WithParameters(SeparatedList(updatedParameters, node.ParameterList.Parameters.GetSeparators()))
99	                );
100	            }
101	
102	            return newNode;
103	        }
104	
105	        public override SyntaxNode? VisitIdentifierName(IdentifierNameSyntax node)
106	        {
107	            // replace parameter names
108	            if (_replacements.TryGetValue(node.Identifier.Text, out var newName))
109	            {
110	                if (string.Equals(newName, node.Identifier.Text, StringComparison.Ordinal))
111	                    return node;
112	
113	                return node.WithIdentifier(Identifier(newName).WithTriviaFrom(node.Identifier));
114	            }
115	
116	            // replace source parameter
117	            if (node.Identifier.Text.Equals(sourceParameter.Identifier.Text, StringComparison.Ordinal))
118	            {
119	                return ctx.Source.WithTriviaFrom(node);
120	            }
121	
122	            // replace additional parameters with their corresponding expressions from the context
123	            // The dictionary uses case-insensitive keys, so ContainsKey serves as a fast negative check.
124	            // We then verify exact case to avoid replacing unrelated identifiers
125	            // (e.g., property CurrentUserId vs parameter currentUserId).
126	            if (ctx.AdditionalParameters is { } additionalParams && additionalParams.ContainsKey(node.Identifier.Text))
127	            {
128	                foreach (var (key, value) in additionalParams)
129	                {
130	                    if (string.Equals(key, node.Identifier.Text, StringComparison.Ordinal))
131	                        return value.WithTriviaFrom(node);
132	                }
133	            }
134	
135	            return base.VisitIdentifierName(node);
136	        }
137	
138	        public override SyntaxNode? VisitInvocationExpression(InvocationExpressionSyntax node)
139	        {
140	            var annotation = node.GetAnnotations(InlineExpressionRewriter.SyntaxAnnotationKindMapperInvocation).FirstOrDefault();
141	            if (annotation == null || !mappingInvocations.TryGetValue(annotation, out var mapping))
142	            {
143	                return base.VisitInvocationExpression(node);
144	            }
145	
146	            var argument = node.ArgumentList.Arguments[0];
