using Riok.Mapperly.Symbols;
using static Riok.Mapperly.Emit.Syntax.SyntaxFactoryHelper;

namespace Riok.Mapperly.Descriptors.Mappings.UserMappings;

/// <summary>
/// A user implemented generic mapping method (non-partial, with a body),
/// which can have generic type parameters in the source and/or target types.
/// When a concrete type mapping matches via type parameter inference,
/// a corresponding invocation is generated.
/// </summary>
public class UserImplementedGenericMethodMapping(
    string? receiver,
    IMethodSymbol method,
    bool? isDefault,
    MethodParameter sourceParameter,
    ITypeSymbol targetType,
    MethodParameter? referenceHandlerParameter,
    bool isExternal,
    UserImplementedMethodMapping.TargetNullability targetNullability
) : UserImplementedMethodMapping(receiver, method, isDefault, sourceParameter, targetType, referenceHandlerParameter, isExternal, targetNullability)
{
    /// <summary>
    /// Whether a concrete type pair matches this generic mapping, with inferred type arguments.
    /// </summary>
    public bool TryMatchTypes(
        GenericTypeChecker genericTypeChecker,
        ITypeSymbol source,
        ITypeSymbol target,
        out IReadOnlyDictionary<ITypeParameterSymbol, ITypeSymbol> inferredTypes)
    {
        var result = genericTypeChecker.InferAndCheckTypes(
            Method.TypeParameters,
            (SourceType, source),
            (TargetType, target)
        );

        inferredTypes = result.InferredTypes;
        return result.Success;
    }
}

