using static Riok.Mapperly.Emit.Syntax.SyntaxFactoryHelper;

namespace Riok.Mapperly.Descriptors.Mappings.UserMappings;

/// <summary>
/// A concrete invocation wrapper for a user-implemented generic mapping method.
/// Stores the inferred type arguments and generates invocations with explicit type arguments.
/// </summary>
internal class UserImplementedGenericMethodConcreteInvocation(
    UserImplementedGenericMethodMapping genericMapping,
    IReadOnlyList<ITypeSymbol> typeArguments
) : NewInstanceMapping(genericMapping.SourceType, genericMapping.TargetType), INewInstanceUserMapping
{
    public IMethodSymbol Method => genericMapping.Method;

    /// <summary>
    /// This is not a default mapping itself - the generic mapping was used as default.
    /// </summary>
    public bool? Default => genericMapping.Default;

    public bool IsExternal => genericMapping.IsExternal;

    public override ExpressionSyntax Build(TypeMappingBuildContext ctx)
    {
        var methodName = genericMapping.Method.Name;

        if (genericMapping.Method.ReceiverType?.TypeKind == TypeKind.Interface)
        {
            // For interface methods, cast the receiver and use the method name
            var castedReceiver = CastExpression(
                FullyQualifiedIdentifier(genericMapping.Method.ReceiverType),
                ThisExpression()
            );
            var methodExpr = MemberAccess(ParenthesizedExpression(castedReceiver), Identifier(methodName));
            var genericName = GenericName(Identifier(methodName))
                .WithTypeArgumentList(
                    TypeArgumentList(SeparatedList(typeArguments.Select(t => (TypeSyntax)FullyQualifiedIdentifier(t))))
                );
            var genericMethodExpr = MemberAccess(ParenthesizedExpression(castedReceiver), genericName);
            return ctx.SyntaxFactory.Invocation(
                genericMethodExpr,
                ctx.BuildArguments(genericMapping.Method, genericMapping.SourceParameter ?? throw new InvalidOperationException(), genericMapping.ReferenceHandlerParameter)
            );
        }

        var genericMethodName = GenericName(Identifier(methodName))
            .WithTypeArgumentList(
                TypeArgumentList(SeparatedList(typeArguments.Select(t => (TypeSyntax)FullyQualifiedIdentifier(t))))
            );

        return ctx.SyntaxFactory.Invocation(
            genericMethodName,
            ctx.BuildArguments(genericMapping.Method, genericMapping.SourceParameter ?? throw new InvalidOperationException(), genericMapping.ReferenceHandlerParameter)
        );
    }
}

