using Microsoft.CodeAnalysis;
using Microsoft.CodeAnalysis.CSharp.Syntax;
using Riok.Mapperly.Helpers;
using Riok.Mapperly.Symbols;
using static Microsoft.CodeAnalysis.CSharp.SyntaxFactory;
using static Riok.Mapperly.Emit.Syntax.SyntaxFactoryHelper;

namespace Riok.Mapperly.Descriptors.Mappings.UserMappings;

/// <summary>
/// A concrete invocation wrapper for a user-implemented generic mapping method.
/// Stores the inferred type arguments and generates invocations with explicit type arguments.
/// </summary>
internal class UserImplementedGenericMethodConcreteInvocation(
    IMethodSymbol method,
    IReadOnlyList<ITypeSymbol> typeArguments,
    ITypeSymbol sourceType,
    ITypeSymbol targetType
) : NewInstanceMapping(sourceType, targetType), INewInstanceUserMapping
{
    public IMethodSymbol Method { get; } = method;

    /// <summary>
    /// This is not a default mapping itself - the generic mapping was used as default.
    /// </summary>
    public bool? Default => null;

    public bool IsExternal => false;

    public override ExpressionSyntax Build(TypeMappingBuildContext ctx)
    {
        var methodName = Method.Name;

        var genericMethodName = GenericName(Identifier(methodName))
            .WithTypeArgumentList(
                TypeArgumentList(SeparatedList(typeArguments.Select(t => (TypeSyntax)FullyQualifiedIdentifier(t))))
            );

        // Build the source parameter
        var sourceParameter = new MethodParameter(0, Method.Parameters[0].Name, Method.Parameters[0].Type);
        MethodParameter? referenceHandlerParameter = null;
        for (var i = 0; i < Method.Parameters.Length; i++)
        {
            var p = Method.Parameters[i];
            if (p.Ordinal == 1 && !SymbolEqualityComparer.Default.Equals(p.Type, targetType))
            {
                // This is a reference handler or additional parameter, not a target parameter
                referenceHandlerParameter ??= new MethodParameter(p, p.Type);
            }
        }

        return ctx.SyntaxFactory.Invocation(
            genericMethodName,
            ctx.BuildArguments(Method, sourceParameter, referenceHandlerParameter)
        );
    }
}

