/// <summary>
    /// Tries to find a user-implemented generic mapping that matches the given type pair
    /// via type parameter inference.
    /// </summary>
    public INewInstanceMapping? FindGenericUserMapping(
        SimpleMappingBuilderContext ctx,
        TypeMappingKey mappingKey)
    {
        foreach (var genericMapping in mappings.GenericUserMappings)
        {
            if (genericMapping.TryMatchTypes(ctx.GenericTypeChecker, mappingKey.Source, mappingKey.Target, out var inferredTypes))
            {
                // The method's type parameters are in the order of the generic method definition.
                // We need to produce type arguments in the same order.
                var typeArguments = genericMapping.Method.TypeParameters
                    .Select(tp => inferredTypes[tp])
                    .ToList();
                return genericMapping.CreateConcreteInvocation(typeArguments, mappingKey.Source, mappingKey.Target);
            }
        }

        return null;
    }

